function ResultsDisplay({ result }) {
  return (
    <div>
      <h3>Results</h3>
      <p>
        Sequence:
        {result.sequence.join(" → ")}
      </p>
      <p>
        Total Seek Time:
        {result.total_seek_time}
      </p>
      <p>
        Average Seek Time:
        {result.average_seek_time}
      </p>
    </div>
  );
}
export default ResultsDisplay;
